// dashboard/services/iteration.service.ts
export class IterationService {
  /**
   * 回滚到指定迭代
   */
  async rollback(iterationId: number): Promise<void> {
    const iteration = await this.findById(iterationId);
    if (!iteration) {
      throw new Error('Iteration not found');
    }

    // 使用 git checkout 回滚
    const { execSync } = require('child_process');
    execSync(`git checkout ${iteration.commitHash}`, {
      cwd: this.projectPath
    });

    // 更新状态
    await this.update(iterationId, { status: 'rolled_back' });
  }

  /**
   * 对比两个迭代
   */
  async diff(iterationId1: number, iterationId2: number): Promise<any> {
    const iter1 = await this.findById(iterationId1);
    const iter2 = await this.findById(iterationId2);

    const { execSync } = require('child_process');
    const diff = execSync(
      `git diff ${iter1.commitHash} ${iter2.commitHash}`,
      { encoding: 'utf-8' }
    );

    return {
      iteration1: iter1,
      iteration2: iter2,
      diff: diff
    };
  }
}

