      this.metrics.agentExecutionTimes.set(agentName, []);
    }
    this.metrics.agentExecutionTimes.get(agentName)!.push(executionTime);
  }

  getAverageExecutionTime(agentName: string): number {
    const times = this.metrics.agentExecutionTimes.get(agentName) || [];
    if (times.length === 0) return 0;
    return times.reduce((a, b) => a + b, 0) / times.length;
  }

