#### ✨ 改进方案

##### 1. 添加超时控制
```typescript
// src/base-agent.ts
export abstract class BaseAgent {
  protected timeoutMs?: number; // 新增：超时时间（毫秒）

  /**
   * 设置 Agent 执行超时
   * @param timeoutMs - 超时时间（毫秒），0 表示无限制
   */
  setTimeout(timeoutMs: number): void {
    this.timeoutMs = timeoutMs;
  }

  async *execute(prompt: string, timeoutMs?: number): AsyncGenerator<any> {
    const actualTimeout = timeoutMs ?? this.timeoutMs;

    // 使用 AbortController 实现超时和取消
    const controller = new AbortController();
    const timeoutId = actualTimeout 
      ? setTimeout(() => controller.abort(), actualTimeout)
      : null;

    try {
      // 执行 Agent 逻辑
      for await (const message of query({...})) {
        yield message;
      }
    } catch (error) {
      if (error.name === 'AbortError') {
        throw new AgentTimeoutError(`Agent 执行超时 (${actualTimeout}ms)`);
      }
      throw error;
    } finally {
      if (timeoutId) clearTimeout(timeoutId);
    }
  }
}
```

##### 2. 实现取消机制
```typescript
// src/agents/agent-executor.ts (新文件)
export class AgentExecutor {
  private abortController?: AbortController;

  /**
   * 执行 Agent（支持取消）
   */
  async execute(
    agent: BaseAgent, 
    prompt: string, 
    timeoutMs?: number
  ): Promise<string> {
    this.abortController = new AbortController();
    const timeoutId = timeoutMs 
      ? setTimeout(() => this.abortController!.abort(), timeoutMs)
      : null;

    try {
      const result = await agent.executeAndCollect(prompt);
      return result;
    } catch (error) {
      if (error.name === 'AbortError') {
        throw new AgentCancelledError('Agent 执行被取消');
      }
      throw error;
    } finally {
      if (timeoutId) clearTimeout(timeoutId);
    }
  }

  /**
   * 取消正在执行的 Agent
   */
  cancel(): void {
    if (this.abortController) {
      this.abortController.abort();
    }
  }
}
```

