// src/auto-iteration.ts
export class AutoIterationEngine {
  private readonly DEFAULT_AGENT_TIMEOUT = 5 * 60 * 1000; // 5 分钟

  async executeAgents(task: string): Promise<void> {
    const executor = new AgentExecutor();

    // 设置全局超时处理
    process.on('SIGINT', () => {
      console.log('收到取消信号，正在停止 Agent...');
      executor.cancel();
    });

    for (const [name, agent] of Object.entries(this.agents)) {
      try {
        console.log(`执行 ${name}...`);
        const result = await executor.execute(
          agent,
          task,
          this.DEFAULT_AGENT_TIMEOUT
        );
        console.log(`${name} 完成`);
      } catch (error) {
        if (error instanceof AgentTimeoutError) {
          console.error(`${name} 超时，跳过`);
          continue;
        }
        throw error;
      }
    }
  }
}
